//! Regression test for https://github.com/dmtrKovalenko/ffs.nvim/issues/381
//!
//! Directory (`PathSegment`) and file-path (`FilePath`) constraints must
//! return results on every platform. Indexed paths on Windows use native
//! backslash separators, so constraint matching has to accept either `/`
//! or `\\` as a path boundary.

use std::fs;
use std::path::Path;
use tempfile::TempDir;

use ffs_search::file_picker::FilePicker;
use ffs_search::grep::{GrepMode, GrepSearchOptions, parse_grep_query};
use ffs_search::{Constraint, FilePickerOptions, FuzzySearchOptions, PaginationArgs, QueryParser};

fn create_picker(base: &Path, specs: &[(&str, &str)]) -> FilePicker {
    for (rel, contents) in specs {
        let full_path = base.join(rel);
        if let Some(parent) = full_path.parent() {
            fs::create_dir_all(parent).unwrap();
        }
        fs::write(&full_path, contents).unwrap();
    }
    let mut picker = FilePicker::new(FilePickerOptions {
        base_path: base.to_string_lossy().to_string(),
        enable_mmap_cache: false,
        watch: false,
        ..Default::default()
    })
    .expect("failed to create FilePicker");
    picker.collect_files().expect("failed to collect files");
    picker
}

fn plain_opts() -> GrepSearchOptions {
    GrepSearchOptions {
        max_file_size: 10 * 1024 * 1024,
        max_matches_per_file: 200,
        smart_case: true,
        file_offset: 0,
        page_limit: 200,
        mode: GrepMode::PlainText,
        time_budget_ms: 0,
        before_context: 0,
        after_context: 0,
        classify_definitions: false,
        trim_whitespace: false,
        abort_signal: None,
    }
}

